### Vitest coverage â€” `__tests__/RateLimitIndicator.test.tsx`

Mock `@tauri-apps/api/core` `invoke` with `vi.fn()`. Project already does this in other component tests â€” copy the pattern.

Minimum cases (~3 tests):
1. **Healthy render**: invoke returns a status with `core.remaining=4500/limit=5000`; component renders `GH: 4500/5000` with `--healthy` class after the initial fetch fires (use `vi.advanceTimersByTime(INITIAL_FETCH_DELAY_MS + 50)` + `await waitFor`).
2. **Critical render**: invoke returns `core.remaining=100/limit=5000` (2%); class is `--critical`.
3. **Tooltip on click**: click the button â†’ tooltip rows for Core/Search/GraphQL appear with formatted reset times.

Test file structure:
```tsx
import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
import { render, screen, fireEvent, waitFor, act } from "@testing-library/react";
import { RateLimitIndicator } from "../RateLimitIndicator";

vi.mock("@tauri-apps/api/core", () => ({
  invoke: vi.fn(),
}));
import { invoke } from "@tauri-apps/api/core";

beforeEach(() => {
  vi.useFakeTimers();
  vi.mocked(invoke).mockReset();
});
afterEach(() => {
  vi.useRealTimers();
});

function mkStatus(overrides: Partial<RateLimitBucket> = {}) {
  const base = { limit: 5000, used: 500, remaining: 4500, reset: Math.floor(Date.now() / 1000) + 3600 };
  return {
    core: { ...base, ...overrides },
    search: { limit: 30, used: 0, remaining: 30, reset: base.reset },
    graphql: { limit: 5000, used: 100, remaining: 4900, reset: base.reset },
    fetchedAtEpoch: Math.floor(Date.now() / 1000),
  };
}

describe("RateLimitIndicator", () => {
  it("renders healthy state after initial fetch", async () => {
    vi.mocked(invoke).mockResolvedValue(mkStatus());
    render(<RateLimitIndicator />);
    await act(async () => { vi.advanceTimersByTime(2000); });
    await waitFor(() => expect(screen.getByText(/GH: 4500\/5000/)).toBeInTheDocument());
    expect(screen.getByRole("button")).toHaveClass("rate-limit-indicator--healthy");
  });

  it("renders critical state when remaining < 10%", async () => {
    vi.mocked(invoke).mockResolvedValue(mkStatus({ remaining: 100 }));
    render(<RateLimitIndicator />);
    await act(async () => { vi.advanceTimersByTime(2000); });
    await waitFor(() => expect(screen.getByRole("button")).toHaveClass("rate-limit-indicator--critical"));
  });

  it("toggles tooltip on click and shows all three buckets", async () => {
    vi.mocked(invoke).mockResolvedValue(mkStatus());
    render(<RateLimitIndicator />);
    await act(async () => { vi.advanceTimersByTime(2000); });
    const btn = await screen.findByRole("button");
